    died = False
    for i in range(n):
        watered = a[i]
        if watered == 0:
            if i > 0 and not was_yesterday:
                died = True
                break
            # no growth
        else:
            if was_yesterday:
                height += 5
            else:
                height += 1
        was_yesterday = (watered == 1)

    if died:
        print(-1)
    else:
        print(height)

