import sys
from math import gcd

input = sys.stdin.read
data = input().split()

index = 0
t = int(data[index])
index += 1

for _ in range(t):
    n = int(data[index])
    index += 1

    freq = [0] * 30
    for i in range(n):
        ai = int(data[index])
        index += 1
        for b in range(30):
            if (ai & (1 << b)):
                freq[b] += 1

    G = 0
    for f in freq:
        G = gcd(G, f)

    if G == 0:
        ks = list(range(1, n + 1))
    else:
        divisors = set()
        sq = int(G ** 0.5) + 1
        for i in range(1, sq):
            if G % i == 0:
                divisors.add(i)
                divisors.add(G // i)
        if G % sq == 0:
            divisors.add(sq)
        ks = sorted(divisors)

    print(' '.join(map(str, ks)))

