def get_len(x):
    return len(str(x))

input = sys.stdin.read
data = input().split()

index = 0
t = int(data[index])
index += 1

for _ in range(t):
    x1 = int(data[index])
    p1 = int(data[index + 1])
    index += 2
    x2 = int(data[index])
    p2 = int(data[index + 1])
    index += 2

    len1 = get_len(x1)
    len2 = get_len(x2)
    d1 = len1 + p1
    d2 = len2 + p2

    if d1 > d2:
        print('>')
    elif d1 < d2:
        print('<')
    else:
        delta = p1 - p2
        if delta >= 0:
            val1 = x1 * (10 ** delta)
            if val1 > x2:
                print('>')
            elif val1 < x2:
                print('<')
            else:
                print('=')
        else:
            absd = -delta
            val2 = x2 * (10 ** absd)
            if x1 > val2:
                print('>')
            elif x1 < val2:
                print('<')
            else:
                print('=')

